- Initialize Next.js app: `npx create-next-app@latest supabase-nextjs`
- Install Supabase client: `npm install @supabase/supabase-js`
- Create `.env.local` file with Supabase credentials:
  ```
  SUPABASE_URL=https://your-project.supabase.co
  SUPABASE_ANON_KEY=your-anon-key
  ```
- Import Supabase client in your component:
  ```javascript
  import { createClient } from '@supabase/supabase-js';
  const supabase = createClient(process.env.SUPABASE_URL, process.env.SUPABASE_ANON_KEY);
  ```
- Create a form with file input and handle `onChange` to upload files:
  ```javascript
  const handleFileChange = async (event) => {
    const file = event.target.files[0];
    if (file) {
      const { data, error } = await supabase.storage.from('your-bucket-name').upload(file.name, file);
      if (error) console.error(error);
      else console.log(data);
    }
  };
  ```
- Use `createClientComponentClient` for server-side rendering:
  ```javascript
  import { createClientComponentClient } from '@supabase/auth-helpers-nextjs';
  const supabase = createClientComponentClient();
  ```
- Retrieve session token and exchange for session:
  ```javascript
  const code = req.query.code;
  const { data, error } = await supabase.auth.exchangeCodeForSession(code);
  if (error) console.error(error);
  else {
    // Store session in storage mechanism
  }
  ```

